package org.eclipse.rdf4j.sail.base;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.List;
import java.util.Optional;
import java.util.Set;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Resource;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.algebra.BindingSetAssignment;
import org.eclipse.rdf4j.query.algebra.Compare;
import org.eclipse.rdf4j.query.algebra.Filter;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.ValueConstant;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.evaluation.QueryBindingSet;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.JoinOrderPlanner;
import org.junit.jupiter.api.Test;

class SketchBasedJoinEstimatorJoinOrderPlannerTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void planJoinOrderSupportsBindingSetAssignmentsAndSimpleFilters() {
		StubSailStore store = new StubSailStore();
		Resource s1 = VF.createIRI("urn:s1");
		Resource s2 = VF.createIRI("urn:s2");
		IRI follows = VF.createIRI("urn:follows");
		IRI name = VF.createIRI("urn:name");
		store.add(VF.createStatement(s1, follows, VF.createIRI("urn:x1")));
		store.add(VF.createStatement(s2, follows, VF.createIRI("urn:x2")));
		store.add(VF.createStatement(s1, name, VF.createLiteral("alice")));
		store.add(VF.createStatement(s2, name, VF.createLiteral("bob")));

		SketchBasedJoinEstimator estimator = new SketchBasedJoinEstimator(store, config());
		estimator.rebuildOnceSlow();

		BindingSetAssignment bindings = new BindingSetAssignment();
		QueryBindingSet row1 = new QueryBindingSet();
		row1.addBinding("s", s1);
		QueryBindingSet row2 = new QueryBindingSet();
		row2.addBinding("s", s2);
		bindings.setBindingSets(List.<BindingSet>of(row1, row2));

		StatementPattern followsPattern = pattern("s", follows, "x");
		StatementPattern namePattern = pattern("s", name, "name");
		Filter filteredName = new Filter(namePattern,
				new Compare(Var.of("name"), new ValueConstant(VF.createLiteral("alice")), Compare.CompareOp.EQ));

		List<TupleExpr> args = List.of(bindings, followsPattern, filteredName);
		Optional<JoinOrderPlanner.JoinOrderPlan> plan = estimator.planJoinOrder(args, Set.of(),
				JoinOrderPlanner.Algorithm.GREEDY);

		assertTrue(plan.isPresent(), "Expected planner to support BindingSetAssignment + simple Filter join arguments");
		List<TupleExpr> orderedArgs = plan.get().getOrderedArgs();
		assertEquals(args.size(), orderedArgs.size());
		assertTrue(orderedArgs.containsAll(args));
	}

	@Test
	void planJoinOrderHandlesMultipleJoinVariablesWithoutGlobalCommonVar() {
		StubSailStore store = new StubSailStore();
		IRI pA = VF.createIRI("urn:pA");
		IRI pB = VF.createIRI("urn:pB");
		IRI pC = VF.createIRI("urn:pC");

		for (int i = 0; i < 8; i++) {
			Resource s = VF.createIRI("urn:s" + i);
			IRI o = VF.createIRI("urn:o" + i);
			IRI x = VF.createIRI("urn:x" + i);
			IRI z = VF.createIRI("urn:z" + i);
			store.add(VF.createStatement(s, pA, o));
			store.add(VF.createStatement(s, pB, x));
			store.add(VF.createStatement(x, pC, z));
		}

		SketchBasedJoinEstimator estimator = new SketchBasedJoinEstimator(store, config());
		estimator.rebuildOnceSlow();

		StatementPattern a = pattern("s", pA, "o");
		StatementPattern b = pattern("s", pB, "x");
		StatementPattern c = pattern("x", pC, "z");
		List<TupleExpr> args = List.of(a, b, c);

		Optional<JoinOrderPlanner.JoinOrderPlan> dpPlan = estimator.planJoinOrder(args, Set.of(),
				JoinOrderPlanner.Algorithm.DYNAMIC_PROGRAMMING);
		Optional<JoinOrderPlanner.JoinOrderPlan> greedyPlan = estimator.planJoinOrder(args, Set.of(),
				JoinOrderPlanner.Algorithm.GREEDY);

		assertTrue(dpPlan.isPresent(), "Expected dynamic programming planner to produce a join order");
		assertTrue(greedyPlan.isPresent(), "Expected greedy planner to produce a join order");
		assertEquals(args.size(), dpPlan.get().getOrderedArgs().size());
		assertTrue(dpPlan.get().getOrderedArgs().containsAll(args));
		assertEquals(args.size(), greedyPlan.get().getOrderedArgs().size());
		assertTrue(greedyPlan.get().getOrderedArgs().containsAll(args));
	}

	@Test
	void planJoinOrderPrefersBindingSetAssignmentThatBindsForeignVars() {
		StubSailStore store = new StubSailStore();
		IRI pA = VF.createIRI("urn:pA");
		IRI pB = VF.createIRI("urn:pB");
		IRI y = VF.createIRI("urn:y");

		BindingSetAssignment bindings = new BindingSetAssignment();
		List<BindingSet> bindingSets = new java.util.ArrayList<>();

		for (int i = 0; i < 512; i++) {
			Resource s = VF.createIRI("urn:s" + i);
			IRI x = VF.createIRI("urn:x" + i);
			store.add(VF.createStatement(s, pA, x));
			QueryBindingSet row = new QueryBindingSet();
			row.addBinding("s", s);
			bindingSets.add(row);
		}
		store.add(VF.createStatement(VF.createIRI("urn:x0"), pB, y));

		bindings.setBindingSets(bindingSets);

		SketchBasedJoinEstimator estimator = new SketchBasedJoinEstimator(store, config());
		estimator.rebuildOnceSlow();

		StatementPattern a = pattern("s", pA, "x");
		StatementPattern b = pattern("x", pB, "y");
		List<TupleExpr> args = List.of(a, b, bindings);

		Optional<JoinOrderPlanner.JoinOrderPlan> plan = estimator.planJoinOrder(args, Set.of(),
				JoinOrderPlanner.Algorithm.GREEDY);

		assertTrue(plan.isPresent(), "Expected planner to produce a plan");
		assertEquals(bindings, plan.get().getOrderedArgs().get(0),
				"BindingSetAssignment that binds join vars should be selected first");
	}

	private static SketchBasedJoinEstimator.Config config() {
		return SketchBasedJoinEstimator.Config.defaults()
				.withNominalEntries(64)
				.withThrottleEveryN(1)
				.withThrottleMillis(0)
				.withRefreshSleepMillis(5);
	}

	private static StatementPattern pattern(String subjVar, IRI pred, String objVar) {
		return new StatementPattern(Var.of(subjVar), Var.of("p", pred), Var.of(objVar));
	}
}
